137	func updateArgList(deployment *appsv1.Deployment, istiocsr *v1alpha1.IstioCSR) {
138		istiocsrConfigs := istiocsr.Spec.IstioCSRConfig
139		// Default clusterID to "Kubernetes" if not provided.
140		clusterID := defaultClusterID
141		if istiocsrConfigs.Server != nil && istiocsrConfigs.Server.ClusterID != "" {
142			clusterID = istiocsrConfigs.Server.ClusterID
143		}
144		args := []string{
145			fmt.Sprintf("--log-level=%d", istiocsrConfigs.LogLevel),
146			fmt.Sprintf("--log-format=%s", istiocsrConfigs.LogFormat),
147			"--metrics-port=9402", "--readiness-probe-port=6060", "--readiness-probe-path=/readyz",
148			fmt.Sprintf("--certificate-namespace=%s", istiocsrConfigs.Istio.Namespace),
149			"--issuer-enabled=true", "--preserve-certificate-requests=false",
150			fmt.Sprintf("--issuer-name=%s", istiocsrConfigs.CertManager.IssuerRef.Name),
151			fmt.Sprintf("--issuer-kind=%s", istiocsrConfigs.CertManager.IssuerRef.Kind),
152			fmt.Sprintf("--issuer-group=%s", istiocsrConfigs.CertManager.IssuerRef.Group),
153			fmt.Sprintf("--root-ca-file=%s/%s", caVolumeMountPath, IstiocsrCAKeyName),
154			fmt.Sprintf("--serving-certificate-dns-names=cert-manager-istio-csr.%s.svc", istiocsr.GetNamespace()),
155			fmt.Sprintf("--serving-certificate-duration=%.0fm", istiocsrConfigs.IstiodTLSConfig.CertificateDuration.Minutes()),
156			fmt.Sprintf("--trust-domain=%s", istiocsrConfigs.IstiodTLSConfig.TrustDomain),
157			fmt.Sprintf("--cluster-id=%s", clusterID),
158			fmt.Sprintf("--max-client-certificate-duration=%.0fm", istiocsrConfigs.IstiodTLSConfig.MaxCertificateDuration.Minutes()),
159			"--serving-address=0.0.0.0:6443",
160			fmt.Sprintf("--serving-certificate-key-size=%d", istiocsrConfigs.IstiodTLSConfig.PrivateKeySize),
161			fmt.Sprintf("--serving-signature-algorithm=%s", istiocsrConfigs.IstiodTLSConfig.PrivateKeyAlgorithm),
162			"--enable-client-cert-authenticator=false",
163			fmt.Sprintf("--leader-election-namespace=%s", istiocsrConfigs.Istio.Namespace),
164			"--disable-kubernetes-client-rate-limiter=false", "--istiod-cert-enabled=false",
165			fmt.Sprintf("--istiod-cert-namespace=%s", istiocsrConfigs.Istio.Namespace),
166			fmt.Sprintf("--istiod-cert-duration=%.0fm", istiocsrConfigs.IstiodTLSConfig.CertificateDuration.Minutes()),
167			fmt.Sprintf("--istiod-cert-renew-before=%.0fm", istiocsrConfigs.IstiodTLSConfig.CertificateRenewBefore.Minutes()),
168			fmt.Sprintf("--istiod-cert-key-algorithm=%s", istiocsrConfigs.IstiodTLSConfig.PrivateKeyAlgorithm),
169			fmt.Sprintf("--istiod-cert-key-size=%d", istiocsrConfigs.IstiodTLSConfig.PrivateKeySize),
170			fmt.Sprintf("--istiod-cert-additional-dns-names=%s", strings.Join(istiocsr.Spec.IstioCSRConfig.IstiodTLSConfig.CertificateDNSNames, ",")),
171			fmt.Sprintf("--istiod-cert-istio-revisions=%s", strings.Join(istiocsrConfigs.Istio.Revisions, ",")),
172		}
173	
174		// Add configmap-namespace-selector argument if configured
175		if istiocsrConfigs.IstioDataPlaneNamespaceSelector != "" {
176			args = append(args, fmt.Sprintf("--configmap-namespace-selector=%s", istiocsrConfigs.IstioDataPlaneNamespaceSelector))
177		}
178	
179		for i, container := range deployment.Spec.Template.Spec.Containers {
180			if container.Name == istiocsrContainerName {
181				deployment.Spec.Template.Spec.Containers[i].Args = args
182			}
183		}
184	}
