188			return nil
189		}
190		if err := common.ValidateResourceRequirements(istiocsr.Spec.IstioCSRConfig.Resources,
191			field.NewPath("spec", "istioCSRConfig")); err != nil {
192			return err
193		}
194		for i := range deployment.Spec.Template.Spec.Containers {
195			deployment.Spec.Template.Spec.Containers[i].Resources = istiocsr.Spec.IstioCSRConfig.Resources
196		}
197		return nil
198	}
