236	func (r *Reconciler) assertIssuerRefExists(istiocsr *v1alpha1.IstioCSR) error {
237		issuerRefKind := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Kind)
238		if issuerRefKind != clusterIssuerKind && issuerRefKind != issuerKind {
239			return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "spec.istioCSRConfig.certManager.issuerRef.kind can be any of `%s` or `%s`, configured: %s", clusterIssuerKind, issuerKind, issuerRefKind)
240		}
241	
242		issuerRefGroup := strings.ToLower(istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Group)
243		if issuerRefGroup != issuerGroup {
244			return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "spec.istioCSRConfig.certManager.issuerRef.group can be only `%s`, configured: %s", issuerGroup, issuerRefGroup)
245		}
246	
247		obj, err := r.getIssuer(istiocsr)
248		if err != nil {
249			return common.FromClientError(err, "failed to fetch issuer")
250		}
251	
252		var issuerConfig certmanagerv1.IssuerConfig
253		switch issuerRefKind {
254		case clusterIssuerKind:
255			clusterIssuer, ok := obj.(*certmanagerv1.ClusterIssuer)
256			if !ok {
257				return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "failed to convert to ClusterIssuer")
258			}
259			issuerConfig = clusterIssuer.Spec.IssuerConfig
260		case issuerKind:
261			issuer, ok := obj.(*certmanagerv1.Issuer)
262			if !ok {
263				return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "failed to convert to Issuer")
264			}
265			issuerConfig = issuer.Spec.IssuerConfig
266		}
267		if issuerConfig.ACME != nil {
268			return common.NewIrrecoverableError(errInvalidIssuerRefConfig, "spec.istioCSRConfig.certManager.issuerRef uses unsupported ACME issuer")
269		}
270	
271		if err := r.updateWatchLabel(obj, istiocsr); err != nil {
272			return common.FromClientError(err, "failed to update watch label on cert-manager issuer %s", istiocsr.Spec.IstioCSRConfig.CertManager.IssuerRef.Name)
273		}
274	
275		return nil
276	}
